+    for (var b: u32 = 0u; b < n_blocks; b = b + 1u) {
+        let scale: f32 = f32(w_scales[expert_scale_base + b]);
+        let zp_byte = load_byte(&w_zp, expert_zp_base + (b >> 1u));
+        let zp_nib = select(zp_byte & 0xFu, (zp_byte >> 4u) & 0xFu, (b & 1u) == 1u);
