+enable f16;
+
+struct Dims { T: u32, H: u32, head_dim: u32, _pad: u32 };
+
+@group(0) @binding(0) var<uniform> dims: Dims;
+@group(0) @binding(1) var<storage, read_write> qk: array<f16>;
