+    let head_base = (t * dims.H + h) * dims.head_dim;
+    let a: f16 = qk[head_base + 2u * p];
+    let b: f16 = qk[head_base + 2u * p + 1u];
+
+    let ac: f16 = a * c;
+    let bs: f16 = b * s;
+    let bc: f16 = b * c;
+    let as_: f16 = a * s;
+
+    qk[head_base + 2u * p]      = ac - bs;
+    qk[head_base + 2u * p + 1u] = bc + as_;
+}

