+<!doctype html>
+<html>
+  <head>
+    <meta charset="utf-8" />
+    <title>textsift conformance — shader fixture dump</title>
+  </head>
+  <body>
+    <pre id="out">starting</pre>
+    <script type="module">
+      // Runs each registered shader via browser WebGPU on a
+      // deterministic seeded input, dumps inputs + outputs to
+      // window.__fixtures so the Playwright spec can serialize them
+      // as binary files. Native conformance tests then load those
+      // files and assert byte-equality against `wgpu-native`.
+      //
+      // Adding a shader = one entry in SHADERS below.
+
+      import { f32_to_f16, pack_f16, unpack_f16, makeRng } from "/tests/conformance/fp16.js";
+
+      // Fetch WGSL straight from the .wgsl source files — that's the
+      // single source of truth shared with the native Zig binding
+      // (which @embedFiles the same paths). No build-step coupling.
+      async function loadShader(name) {
+        const r = await fetch(`/packages/textsift/src/native/shaders/${name}.wgsl`);
+        if (!r.ok) throw new Error(`fetch ${name}.wgsl: ${r.status}`);
+        return await r.text();
+      }
+
+      const $out = document.getElementById("out");
+      const log = (m) => { $out.textContent += "\n" + m; };
+
+      // Each entry: name, WGSL filename, dims, build-input function,
+      // bindings (in WGSL @binding order), output binding index +
+      // length (in elements).
+      const SHADERS = [
+        {
+          name: "rms_norm",
+          dims: { T: 4, D: 128, eps: 1e-6 },
+          // Returns the binding contents in @binding order. Each entry:
+          //   { dtype: "uniform"|"storage", buffer: ArrayBufferLike }
+          build({ T, D, eps }) {
+            const rng = makeRng(0xc0ffee);
+            const x = new Float32Array(T * D);
+            const gamma = new Float32Array(D);
+            for (let i = 0; i < x.length; i++) x[i] = rng() * 0.5;
+            for (let i = 0; i < gamma.length; i++) gamma[i] = 1.0 + rng() * 0.1;
+            const dimsBuf = new ArrayBuffer(16);
+            const dimsView = new DataView(dimsBuf);
+            dimsView.setUint32(0, T, true);
+            dimsView.setUint32(4, D, true);
+            dimsView.setFloat32(8, eps, true);
+            dimsView.setUint32(12, 0, true); // _pad
+            return {
+              uniform: { binding: 0, bytes: new Uint8Array(dimsBuf) },
+              inputs: [
+                { binding: 1, name: "x", bytes: new Uint8Array(pack_f16(x).buffer) },
+                { binding: 2, name: "gamma", bytes: new Uint8Array(pack_f16(gamma).buffer) },
+              ],
+              output: { binding: 3, elements: T * D, dtype: "f16" },
+              dispatch: [T, 1, 1], // one workgroup per row of T
+            };
+          },
+        },
+      ];
+
+      try {
+        if (!navigator.gpu) throw new Error("no navigator.gpu");
+        const adapter = await navigator.gpu.requestAdapter();
+        if (!adapter) throw new Error("no GPU adapter");
+        if (!adapter.features.has("shader-f16")) throw new Error("no shader-f16");
+        const device = await adapter.requestDevice({ requiredFeatures: ["shader-f16"] });
+
+        const fixtures = {};
+        for (const shader of SHADERS) {
+          log(`\n[${shader.name}]`);
+          const wgsl = await loadShader(shader.name);
+          const built = shader.build(shader.dims);
+          const elemBytes = built.output.dtype === "f16" ? 2 : 4;
+          const outBytes = built.output.elements * elemBytes;
+
+          const module = device.createShaderModule({ code: wgsl });
+          const pipeline = device.createComputePipeline({
+            layout: "auto",
+            compute: { module, entryPoint: "main" },
+          });
+
+          const uBuf = device.createBuffer({
+            size: built.uniform.bytes.byteLength,
+            usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST,
+          });
+          device.queue.writeBuffer(uBuf, 0, built.uniform.bytes);
+
+          const inBufs = built.inputs.map((entry) => {
+            const buf = device.createBuffer({
+              size: entry.bytes.byteLength,
+              usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST,
+            });
+            device.queue.writeBuffer(buf, 0, entry.bytes);
+            return { ...entry, buffer: buf };
+          });
+
+          const outBuf = device.createBuffer({
+            size: outBytes,
+            usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC,
+          });
+          const readback = device.createBuffer({
+            size: outBytes,
+            usage: GPUBufferUsage.MAP_READ | GPUBufferUsage.COPY_DST,
+          });
+
+          const bgEntries = [
+            { binding: built.uniform.binding, resource: { buffer: uBuf } },
+            ...inBufs.map((e) => ({ binding: e.binding, resource: { buffer: e.buffer } })),
+            { binding: built.output.binding, resource: { buffer: outBuf } },
+          ];
+          const bg = device.createBindGroup({
+            layout: pipeline.getBindGroupLayout(0),
+            entries: bgEntries,
+          });
+
+          const enc = device.createCommandEncoder();
+          const pass = enc.beginComputePass();
+          pass.setPipeline(pipeline);
+          pass.setBindGroup(0, bg);
+          pass.dispatchWorkgroups(...built.dispatch);
+          pass.end();
+          enc.copyBufferToBuffer(outBuf, 0, readback, 0, outBytes);
+          device.queue.submit([enc.finish()]);
+          await readback.mapAsync(GPUMapMode.READ);
+          const outBytesView = new Uint8Array(readback.getMappedRange().slice(0));
+          readback.unmap();
+          log(`  output: ${outBytes} bytes`);
+
+          fixtures[shader.name] = {
+            dims: shader.dims,
+            uniform: Array.from(built.uniform.bytes),
+            inputs: built.inputs.map((e) => ({ name: e.name, bytes: Array.from(e.bytes) })),
+            output: { dtype: built.output.dtype, bytes: Array.from(outBytesView) },
+            dispatch: built.dispatch,
+            workgroupSize: [64, 1, 1], // matches the shaders we ship today
+          };
+        }
+        window.__fixtures = fixtures;
+        log("\ndone");
+      } catch (e) {
+        window.__fixtures = { error: String(e), stack: e.stack };
+        log("ERROR: " + e);
+        throw e;
+      }
+    </script>
+  </body>
+</html>

